import { Injectable } from '@angular/core';
import { Observable } from 'rxjs';
import { ApiService } from './api.service';
import { PlatformSummaryDto, OrgReportDto, CourseReportDto, UserProgressReportDto } from '../models/report.models';

@Injectable({ providedIn: 'root' })
export class ReportService {
  constructor(private api: ApiService) {}

  getPlatformSummary(): Observable<PlatformSummaryDto> {
    return this.api.get<PlatformSummaryDto>('reports/platform');
  }

  getOrgReport(orgId: number): Observable<OrgReportDto> {
    return this.api.get<OrgReportDto>(`reports/org/${orgId}`);
  }

  getCourseReport(courseId: number, orgId?: number): Observable<CourseReportDto> {
    return this.api.get<CourseReportDto>(`reports/course/${courseId}`, orgId ? { orgId } : undefined);
  }

  getUserProgressReport(userId: number): Observable<UserProgressReportDto> {
    return this.api.get<UserProgressReportDto>(`reports/user/${userId}`);
  }

  /** Current user's own progress — works for all roles. */
  getMyProgressReport(): Observable<UserProgressReportDto> {
    return this.api.get<UserProgressReportDto>('reports/me');
  }
}
